    /**
     * Show all the invalid properties with reasons.
     *
     * @return string[] invalid properties with reasons
     */
    public function listInvalidProperties(): array
    {
        $invalidProperties = parent::listInvalidProperties();

        $allowedValues = $this->getAppointmentGenderPreferenceAllowableValues();
        if (!is_null($this->container['AppointmentGenderPreference']) && !in_array($this->container['AppointmentGenderPreference'], $allowedValues, true)) {
            $invalidProperties[] = sprintf(
                "invalid value for 'AppointmentGenderPreference', must be one of '%s'",
                implode("', '", $allowedValues)
            );
        }

        $allowedValues = $this->getActionAllowableValues();
        if (!is_null($this->container['Action']) && !in_array($this->container['Action'], $allowedValues, true)) {
            $invalidProperties[] = sprintf(
                "invalid value for 'Action', must be one of '%s'",
                implode("', '", $allowedValues)
            );
        }

        return $invalidProperties;
    }


